mapper.select:
SELECT perm.id, perm.user_id, usr.username, usr.real_name, perm.provider_config_id, cfg.provider_name, perm.can_manage_provider, perm.can_use_ai, perm.can_train_skill, perm.can_publish_skill, perm.can_use_agent, perm.can_run_analysis, perm.status, perm.grant_time FROM ai_user_ai_permission perm INNER JOIN sys_user usr ON usr.id = perm.user_id AND usr.is_deleted = FALSE INNER JOIN ai_provider_config cfg ON cfg.id = perm.provider_config_id AND cfg.is_deleted = FALSE WHERE 1 = 1
AND perm.user_id = #{request.userId}
AND perm.provider_config_id = #{request.providerConfigId}
AND perm.status = #{request.status}
ORDER BY perm.grant_time DESC, perm.id DESC

SELECT id, user_id, provider_config_id, can_manage_provider, can_use_ai, can_train_skill,
       can_publish_skill, can_use_agent, can_run_analysis, status, grant_time, grant_user
FROM ai_user_ai_permission
WHERE user_id = #{userId}
  AND provider_config_id = #{providerConfigId}

